var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"행색과 행동 양상으로 미루어보아 민병대 분들이시군요. 소문은 익히 들었습니다.","JPN":"身なりと行動からして民兵隊の方々ですね。噂は聞いております。","ENG":"Judging by your behavior, you must be the Militia. I've heard a lot about you.","TWN":"從你們的裝扮和行動看來，應該是民兵隊的吧？久仰大名。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제 행적 때문에 오셨으리라고 짐작되지만……. 쉽게 목숨을 내어드릴 수는 없군요.","JPN":"以前、私が犯した罪の件でお越しになったのでしょうが……そう簡単に命を奪われるわけにはいきません。","ENG":"I'm sure you're here to make me pay for what I did... But I won't surrender that easily.","TWN":"雖然我有猜到你們是為我而來的……但我無法輕易交出自己的性命。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"말도 안 돼. 이게 보통 사람의 완력이라고?","JPN":"あり得ない。これが普通の人間の腕力だって？","ENG":"What the heck? No normal human can be this powerful...!","TWN":"太誇張，這是普通人的腕力嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"사람은 위기 상황에 처하면 평소와 다른 신체 능력을 발휘한다고 하죠.","JPN":"人は危機状態に陥ると普段とは違う身体能力を発揮すると言われています。","ENG":"Haven't you heard how people display extreme physical strength when they are in life-or-death situations?","TWN":"當人面對危險時，身體會激發出不同於平時的潛能。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 저는 여러분처럼 통증을 느낄 수 없답니다.","JPN":"ですが、私は皆様のように苦痛を感じることができないのです。","ENG":"However, one thing I differ from you all is that I can't feel pain.","TWN":"不過我和你們一樣，是感覺不到疼痛的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"큭……! 빗나갔나!","JPN":"くっ……！　外したか！","ENG":"Kgh...! I missed!","TWN":"唔……！射偏了嗎！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"위기를 경고해 줄 기재가 없으니 항상 위기 상황처럼 긴장하고 지낼 수밖에요.","JPN":"危機を警告してくれる機構がないので、常に危機状態の時のように緊張しているしかありません。","ENG":"And since there is no warning sign for when I'll be attacked, I have no choice but to always stay alert.","TWN":"因為沒有工具可以通知你有危險，所以常常只能處於戒備狀態。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그리고 주위의 기척을 읽는 건, 메이드에게 필수적인 소양이랍니다.","JPN":"それに周囲の気配を感じとるのは、メイドにとって必要不可欠なたしなみです。","ENG":"Furthermore, being able to read the energy around her is one of a maid's required virtues.","TWN":"另外，察覺周圍的動靜是女僕必備的素養。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"빌어먹을, 저 여자에게는 사각도 없나 보군.","JPN":"くそ、あの女には死角もないようだな。","ENG":"Dammit...! It's like this person has no blind spot!","TWN":"該死，那女的似乎沒有盲點！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"안 되겠다. 이유리, 레비아. 타깃과 최대한 멀리 떨어져.","JPN":"仕方ない。カスカベ、レヴィア。なるべくターゲットから遠く離れろ。","ENG":"Forget this. Yuri, Levia, get as far away from the target as possible.","TWN":"這樣不行，李悠麗、莉維亞，盡可能和目標拉開距離。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐? 어떻게 하려고?","JPN":"は？　どうするつもり？","ENG":"What? But why?","TWN":"什麼？你想做什麼？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"설명할 시간 없다! 서둘러!","JPN":"説明する暇はない！　急げ！","ENG":"There's no time to explain! Hurry!","TWN":"我沒時間跟你解釋！動作快！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"우와, 건물이 통째로 무너졌네요? 이게 민우 대장이 준비한 보험이에요?","JPN":"うわ、建物が丸ごと崩れましたよ？　これがマツダ隊長が準備していた保険なんですか？","ENG":"Whoa, the building just collapsed. Is this the backup plan Captain was talking about?","TWN":"哇～整棟樓都垮咧？這就是民宇隊長買的保險嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 부랴부랴 준비했는데 다행히 제대로 터졌군.","JPN":"ああ。急いで準備したんだが、幸いちゃんと爆発したようだな。","ENG":"Yes. I was hurried for it and thank god it worked.","TWN":"沒錯，準備得有點匆促，幸好有順利引爆。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"괜찮나, 이유리?","JPN":"大丈夫か？　カスカベ。","ENG":"You all right, Yuri?","TWN":"李悠麗，你沒事吧？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};